var log = require('logToConsole');
var callInWindow = require('callInWindow');
var copyFromWindow = require('copyFromWindow');
var createQueue = require('createQueue');
var injectScript = require('injectScript');
var makeTableMap = require('makeTableMap');
var sendPixel = require('sendPixel');
var setInWindow = require('setInWindow');

function mergeObjects() {
    var res = {};
    for(var i = 0; i < arguments.length; ++i) {
        for(var x in arguments[i]) {
            res[x] = arguments[i][x];
        }
    }
    return res;
}

function bootstrapFn() {
  var snaptr = copyFromWindow('snaptr');
  if (snaptr) {
    return snaptr;
  }

  setInWindow('snaptr', function() {
    var handler = copyFromWindow('snaptr.handleRequest');
    if (handler) {
      callInWindow('snaptr.handleRequest.apply', null, arguments);
    } else {
      callInWindow('snaptr.queue.push', arguments);
    }
  });
  return copyFromWindow('snaptr');
}

function bootstrap() {
  var existingSnaptr = copyFromWindow('snaptr');
  var snaptr = bootstrapFn();
  createQueue('snaptr.queue');
  setInWindow('snaptr.sendPixelByGTM', sendPixel, true);

  data.integration = "gtm";

  // Console logging is optional and controlled by the enable_console_logging parameter
  // Default: disabled to prevent performance issues during Tag Assistant preview sessions
  // Enable in tag configuration when debugging is needed
  if (data.enable_console_logging) {
    log("data = ", data);
  }

  var additionalInitData = (data.additional_init_data) ? makeTableMap(data.additional_init_data, 'key', 'value') : {};
  var initData = mergeObjects(data, additionalInitData);

  if (data.enable_console_logging) {
    log("initData = ", initData);
  }

  if (initData.pixel_id) {
    snaptr('init', initData.pixel_id, initData);
    if (initData.event_type) {
      snaptr('track', initData.pixel_id, initData.event_type, data);
    }
  }

  if (!existingSnaptr) {
    // Use gateway_url if provided (for Conversions API Gateway with first-party domains)
    // SECURITY NOTE: By default, only sc-static.net and tr.snapchat.com are allowed domains.
    // If using a custom domain, you MUST manually add it to the Script Injection permissions
    // in the ___WEB_PERMISSIONS___ section below. Do NOT add placeholder or example domains
    // as this creates security risks for users.
    var url = data.gateway_url || 'https://sc-static.net/scevent.min.js';
    injectScript(url, data.gtmOnSuccess, data.gtmOnFailure, url);
  }
}

bootstrap();


